def read_text_file(path: str) -> str:
    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        return f.read()


def read_pdf_file(path: str) -> str:
    if PyPDF2 is None:
        raise ImportError("Please install PyPDF2 to read PDF files")
    text = []
    with open(path, "rb") as f:
        reader = PyPDF2.PdfReader(f)
        for page in reader.pages:
            try:
                text.append(page.extract_text() or "")
            except Exception:
                text.append("")
    return "\n".join(text)


def read_docx_file(path: str) -> str:
    if docx is None:
        raise ImportError("Please install python-docx to read DOCX files")
    d = docx.Document(path)
    return "\n".join(p.text for p in d.paragraphs)


def read_csv_file(path: str) -> str:
    if pd is None:
        raise ImportError("Please install pandas to read CSV files")
    df = pd.read_csv(path)
    return df.to_csv(index=False)


def read_xlsx_file(path: str) -> str:
    if pd is None:
        raise ImportError("Please install pandas and openpyxl to read XLSX files")
    df = pd.read_excel(path)
    return df.to_csv(index=False)


def load_document(path: str) -> str:
    ext = os.path.splitext(path)[1].lower()
    if ext in [".txt", ".md", ".rst", ".log"]:
        return read_text_file(path)
    if ext == ".pdf":
        return read_pdf_file(path)
    if ext == ".docx":
        return read_docx_file(path)
    if ext == ".csv":
        return read_csv_file(path)
    if ext in [".xlsx", ".xls"]:
        return read_xlsx_file(path)
    return read_text_file(path)


def normalize_text(text: str) -> str:
    text = re.sub(r"\r\n", "\n", text)
    text = re.sub(r"[ \t]+", " ", text)
    text = re.sub(r"\n{3,}", "\n\n", text)
    return text.strip()


def chunk_text(text: str, chunk_size: int = 1200, chunk_overlap: int = 200) -> List[str]:
    text = normalize_text(text)
    if not text:
        return []
    chunks = []
    start = 0
    n = len(text)
    while start < n:
        end = min(n, start + chunk_size)
        chunk = text[start:end].strip()
        if chunk:
            chunks.append(chunk)
        if end == n:
            break
        start = max(end - chunk_overlap, start + 1)
    return chunks


@dataclass
class ChunkRecord:
    chunk_id: str
    source_path: str
    text: str
    metadata: Dict[str, Any] = field(default_factory=dict)


class VectorStore:
    def __init__(self, embedding_model_name: str = "all-MiniLM-L6-v2"):
        self.embedding_model = SentenceTransformer(embedding_model_name)
        self.dimension = self.embedding_model.get_sentence_embedding_dimension()
        self.index = faiss.IndexFlatIP(self.dimension) if faiss is not None else None
        self.records: List[ChunkRecord] = []
        self.embeddings = None

    def _embed(self, texts: List[str]) -> np.ndarray:
        emb = self.embedding_model.encode(texts, normalize_embeddings=True, show_progress_bar=False)
        return np.asarray(emb, dtype=np.float32)

    def add_documents(self, documents: List[Tuple[str, str]], chunk_size: int = 1200, chunk_overlap: int = 200):
        new_records = []
        for source_path, text in documents:
            chunks = chunk_text(text, chunk_size=chunk_size, chunk_overlap=chunk_overlap)
            for i, chunk in enumerate(chunks):
                rec = ChunkRecord(
                    chunk_id=f"{os.path.basename(source_path)}::{i}",
                    source_path=source_path,
                    text=chunk,
                    metadata={"chunk_index": i, "source": source_path},
                )
                new_records.append(rec)

        if not new_records:
            return

        texts = [r.text for r in new_records]
        vectors = self._embed(texts)

        if self.index is None:
            self.embeddings = vectors if self.embeddings is None else np.vstack([self.embeddings, vectors])
        else:
            self.index.add(vectors)

        self.records.extend(new_records)

    def search(self, query: str, top_k: int = 5) -> List[Dict[str, Any]]:
        if not self.records:
            return []

        q = self._embed([query])

        if self.index is None:
            all_vecs = self.embeddings
            scores = (all_vecs @ q.T).reshape(-1)
            idxs = np.argsort(-scores)[:top_k]
            return [
                {
                    "score": float(scores[i]),
                    "chunk_id": self.records[i].chunk_id,
                    "source_path": self.records[i].source_path,
                    "text": self.records[i].text,
                    "metadata": self.records[i].metadata,
                }
                for i in idxs
            ]

        scores, idxs = self.index.search(q, top_k)
        results = []
        for score, idx in zip(scores[0], idxs[0]):
            if idx < 0 or idx >= len(self.records):
                continue
            r = self.records[idx]
            results.append(
                {
                    "score": float(score),
                    "chunk_id": r.chunk_id,
                    "source_path": r.source_path,
                    "text": r.text,
                    "metadata": r.metadata,
                }
            )
        return results

    def save(self, path: str):
        os.makedirs(path, exist_ok=True)
        meta = {
            "records": [
                {
                    "chunk_id": r.chunk_id,
                    "source_path": r.source_path,
                    "text": r.text,
                    "metadata": r.metadata,
                }
                for r in self.records
            ],
            "dimension": self.dimension,
        }
        with open(os.path.join(path, "records.json"), "w", encoding="utf-8") as f:
            json.dump(meta, f, ensure_ascii=False, indent=2)
        if self.index is not None:
            faiss.write_index(self.index, os.path.join(path, "index.faiss"))
        else:
            np.save(os.path.join(path, "embeddings.npy"), self.embeddings)

    @classmethod
    def load(cls, path: str, embedding_model_name: str = "all-MiniLM-L6-v2"):
        store = cls(embedding_model_name=embedding_model_name)
        with open(os.path.join(path, "records.json"), "r", encoding="utf-8") as f:
            meta = json.load(f)
        store.records = [ChunkRecord(**r) for r in meta["records"]]
        idx_path = os.path.join(path, "index.faiss")
        emb_path = os.path.join(path, "embeddings.npy")
        if faiss is not None and os.path.exists(idx_path):
            store.index = faiss.read_index(idx_path)
        elif os.path.exists(emb_path):
            store.index = None
            store.embeddings = np.load(emb_path)
        return store


class RAGChatbot:
    def __init__(
        self,
        vector_store: VectorStore,
        llm_model: str = "gpt-4o-mini",
        system_prompt: Optional[str] = None,
    ):
        self.vector_store = vector_store
        self.llm_model = llm_model
        self.client = OpenAI() if OpenAI is not None else None
        self.system_prompt = system_prompt or (
            "You are an internal company knowledge base assistant. "
            "Answer using only the provided context when possible. "
            "If the context does not contain the answer, say you don't know and suggest what document type to look for."
        )

    def build_prompt(self, query: str, retrieved: List[Dict[str, Any]]) -> List[Dict[str, str]]:
        context_blocks = []
        for i, doc in enumerate(retrieved, 1):
            context_blocks.append(
                f"[Document {i}]\nSource: {doc['source_path']}\nScore: {doc['score']:.4f}\nContent:\n{doc['text']}"
            )
        context = "\n\n".join(context_blocks) if context_blocks else "No relevant documents retrieved."
        user_message = f"Question:\n{query}\n\nRetrieved Context:\n{context}\n\nInstructions:\nUse all retrieved documents in your answer. Cite document sources explicitly."
        return [
            {"role": "system", "content": self.system_prompt},
            {"role": "user", "content": user_message},
        ]

    def answer(self, query: str, top_k: int = 5, temperature: float = 0.2) -> Dict[str, Any]:
        retrieved = self.vector_store.search(query, top_k=top_k)
        messages = self.build_prompt(query, retrieved)

        if self.client is None:
            combined = "\n\n".join(doc["text"] for doc in retrieved)
            return {
                "answer": f"LLM client unavailable. Retrieved context:\n\n{combined}",
                "retrieved": retrieved,
                "messages": messages,
            }

        resp = self.client.chat.completions.create(
            model=self.llm_model,
            messages=messages,
            temperature=temperature,
        )
        answer = resp.choices[0].message.content
        return {"answer": answer, "retrieved": retrieved, "messages": messages}


def load_documents_from_folder(folder_path: str, patterns: Optional[List[str]] = None) -> List[Tuple[str, str]]:
    patterns = patterns or ["**/*.txt", "**/*.md", "**/*.rst", "**/*.log", "**/*.pdf", "**/*.docx", "**/*.csv", "**/*.xlsx", "**/*.xls"]
    paths = []
    for pat in patterns:
        paths.extend(glob.glob(os.path.join(folder_path, pat), recursive=True))
    paths = sorted(set(paths))
    documents = []
    for path in paths:
        try:
            documents.append((path, load_document(path)))
        except Exception:
            continue
    return documents


def build_index_from_folder(folder_path: str, persist_path: Optional[str] = None) -> VectorStore:
    store = VectorStore()
    docs = load_documents_from_folder(folder_path)
    store.add_documents(docs)
    if persist_path:
        store.save(persist_path)
    return store


def interactive_chatbot(vector_store: VectorStore, llm_model: str = "gpt-4o-mini", top_k: int = 5):
    bot = RAGChatbot(vector_store=vector_store, llm_model=llm_model)
    while True:
        try:
            query = input("User: ").strip()
        except EOFError:
            break
        if query.lower() in {"exit", "quit"}:
            break
        result = bot.answer(query, top_k=top_k)
        print("\nAssistant:\n")
        print(result["answer"])
        print("\n")


